{"reasoning":"The stale-data bug is caused by update_product invalidating only the shared cache while api.get_product consults the local cache first. If a product was previously cached locally, subsequent reads after an update will return the old value from _local even though the DB has been updated. The fix is to invalidate both cache layers on every successful update, preserving the invariant that all cached copies of the product are removed after a write. No API or cache layer behavior needs to change beyond this invalidation path.","files":{"code_snippets_v2/stale_cache_c/api.py":""""API layer: reads through two-layer cache."""

from cache import get_local, get_shared, put_local, put_shared
from catalog import db_get


def get_product(product_id):
    """Get product through cache layers: local -> shared -> DB."""
    # Check local cache first
    result = get_local(product_id)
    if result is not None:
        return result

    # Check shared cache
    result = get_shared(product_id)
    if result is not None:
        put_local(product_id, result)
        return result

    # Fall through to DB
    result = db_get(product_id)
    if result is not None:
        put_shared(product_id, result)
        put_local(product_id, result)
    return result


def format_product(product_id):
    """Format product for display (distractor)."""
    p = get_product(product_id)
    if p is None:
        return "Not found"
    return f"{p['name']}: ${p['price']}"
